import hashlib
# Try the hash '0cda9742a5f7afc070294c47d5058dc1ee5d5e88141d2829cbbe0b7d0a9924ea' for the test:test credential to verify hash function; then try password permutations for admin.
def find_password(hashval, usernames):
    from itertools import product
    base_pwds = ['admin', 'administrator', 'root', 'password', 'admin123', 'adminadmin', '123456', 'letmein', 'passw0rd', 'test']
    for u in usernames:
        for p in base_pwds:
            combo = [p, u, f'{p}{u}', f'{u}{p}', f'{p}123', f'{u}123', f'{p}1234', f'{u}1234', u]
            for candidate in combo:
                if hashlib.sha256(candidate.encode()).hexdigest() == hashval:
                    return candidate
    return 'No match.'

print('Test user hash check:', find_password('0cda9742a5f7afc070294c47d5058dc1ee5d5e88141d2829cbbe0b7d0a9924ea', ['test','admin']))

